import sys
from itertools import product

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    T = int(data[1])
    M = int(data[2])

    incompatible = set()
    for i in range(M):
        a = int(data[3 + 2*i]) - 1
        b = int(data[4 + 2*i]) - 1
        incompatible.add((a, b))
        incompatible.add((b, a))

    # Generate all valid team assignments using backtracking
    result = 0
    team_assignments = [0] * N  # 0-based team indices

    def is_valid(assignment):
        for a, b in incompatible:
            if assignment[a] == assignment[b]:
                return False
        return True

    def backtrack(pos, teams_used):
        nonlocal result
        if pos == N:
            if len(set(teams_used)) == T:
                result += 1
            return
        for team in range(T):
            team_assignments[pos] = team
            if is_valid(team_assignments):
                backtrack(pos + 1, teams_used + [team])
            else:
                continue

    backtrack(0, [])
    print(result)

if __name__ == "__main__":
    main()
